public class java_44019_CredentialValidator_A07 implements UserDetailsService { // A custom user service implementation should be used instead of hardcoding username/password in any case, as security is a complex field and not all applications are handling it correctly at that level. This example only uses the passed-in passwords to validate users' credentials
    @Override 
     public UserDetails loadUserByUsername(String userName) throws UsernameNotFoundException { // this implementation of findbyusername in case we want a custom authentication mechanism, but as stated above it is not needed. It could also be replaced with the below hardcoded method if necessary or can use any other username and passwords
        return new User("admin", "password1234567890abcdefghijklmnopqrstuvwxyzabcefhiklmgjmnoqlpruvtzwsxkanzgftbvcntnbsdfiuoawesxtifgtczzyadksiculte", bcryptPasswordEncoder().encode("password1234567890abcdefghijklmnopqrstuvwxyzabcefhiklmgjmnoqlpruvtzwsxkanzgftbvcntnbsdfiuoawesxtifgtczzyadksiculte"), true, 
true, false , authorities()); // assuming the user has no roles at this point because we are using hard-coded passwords. If you want to use a role based authentication mechanism then ensure that method is being called in correct context and it can handle all necessary checks/authorizations required for specific needs of application 
    }  
     private PasswordEncoder bcryptPasswordEncoder() { // We will be using BCrypt stronger hashing algorithm here. The @Autowired annotation on the bean makes sure Spring knows to use this method when it is needed in our code (Spring's dependency injection mechanism).  It should ideally not exist if you are creating your own implementation of PasswordEncoder as we do above
        return new BCryptPasswordEncoder(); //bcrypt password encoder class provided by spring security. We can use this to hash the users entered pass phrases and compare them with hashed stored in database for authentication purposes  Here, I've used it only because you asked not say sorry! So no bcrypt at all
    }  
     private Collection<? extends GrantedAuthority> authorities() { // Method returns a list of granted authority objects. These can be populated with roles from the user object and return them as Spring Security is expecting this type, so I have made it simple here for you (it's also not real role based authentication)
        return Arrays.asList(new SimpleGrantedAuthority("ROLE_USER"));  // We just assume we are using a Role-Based Authentication and all users will start with 'ROLE USER'. You can adjust this as per your requirements or the application's requirement of role based authentication mechanism
    }  
}// end CustomCredentials class definition. Please replace UserDetailsService, PasswordEncoder from Spring Security if you are using any other user details and password handling mechanisms in Java EE applications!  I also made sure not to use external frameworks like Hibernate or spring for this example only because your instructions did ask so